var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"해, 해치웠나?","JPN":"た、倒したか？","ENG":"I-is it dead?","TWN":"解、解決掉它了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_VAL_NULL","text":{"KOREA":"소림아. 그런 대사 하면 위험하다구!","JPN":"ミズキ、そういう台詞はフラグになっちゃうよ！","ENG":"Sorim, you know what happens when you say that kind of thing!","TWN":"蕭林啊，這種臺詞很危險的！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"......앗, 실수했다!","JPN":"……あっ、やってしまった！","ENG":"Oops, my bad!","TWN":"啊，糟了！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"흐그그...... 그, 그럼 다시 되살아나는 건가?","JPN":"むむっ……い、生き返ってしまうのか？","ENG":"Err, i-is it going to come back to life?","TWN":"啊啊……那、那它是要復活了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"뭐...... 그런 대사로 부활하기엔 좀 많이 조각난 것 같네요.","JPN":"まあ、その台詞で生き返るには、バラバラになりすぎてますわ。","ENG":"Well... it'll probably take more than just words to put all those pieces back together.","TWN":"嗯……都四分五裂成這樣了應該不會因為我說的臺詞復活吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"그보다 그 쪽의 두 아가씨들 어디 출신이라고 했더라? ......코핀 컴퍼니?","JPN":"それより、そこのお二方は……\\nコフィンカンパニー所属だとおっしゃいましたね？","ENG":"By the way, where did you two say you came from? The Coffin Company?","TWN":"不說這個了，那邊那兩位小姐歸屬何處來著？科芬公司？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"보기보다 대단한 실력자들이군요.","JPN":"見かけによらず、素晴らしい実力をお持ちなのですね。","ENG":"You're more impressive than you look.","TWN":"你們比看起來能幹多了啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"나중에 기회가 된다면 저희 프리드웬 기관에도 한 번 방문해 주시면 좋겠어요.","JPN":"ぜひ今度、プリドウェン機関にいらっしゃってください。","ENG":"Why don't you come over to the Prydwen Institution later?","TWN":"希望以後有機會能訪問一次我們普利多溫機關。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"사업상 나눌 만한 이야기들이 많을 것 같으니까요.","JPN":"ビジネスについて、色々とお話をしたいので。","ENG":"I'd love to discuss business with you.","TWN":"我想我們有許多生意上值得一聊的事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"제안은 고맙지만, 그 부분은 우리 부사장과 이야기해 보는 게 좋을 것 같군.","JPN":"ありがたい申し出だが、それはうちの副社長と話した方がいい。","ENG":"Thank you, but you'll have to talk to our vice president about that.","TWN":"謝謝您的邀請，但這個我們還得先和副總商量一下。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"그보다 이걸로 이번 일은 끝난 건가?","JPN":"それより、これで今回の仕事は終わりか？","ENG":"By the way, is this the end of our mission?","TWN":"先不說這個，這次這事兒結束了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"큭...... 크큭...... 크크큭!!","JPN":"クッ……ククッ……クククッ！！","ENG":"Hee... Hee hee... Hee hee hee!","TWN":"哈……哈哈……哈哈哈！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"드디어...... 드디어 성배가 내 손에 들어왔다! 이것만 있으면......!!","JPN":"やっと……やっと、聖杯がこの手に入った！　これさえあれば……！！","ENG":"Finally, the holy grail is in my hand! With this, I can—","TWN":"終於……終於得到聖杯了！只要有這個！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"깜짝이야. 갑자기 왜 저런대?","JPN":"びっくりした。急に何？","ENG":"Oh geez, what's wrong with you all of a sudden?","TWN":"嚇我一跳！ 幹嘛呢突然？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"원하는 걸 받았으면 빨리 확인증이나 찍어달라고.","JPN":"欲しかったものを受け取ったなら、早く確認証を出して。","ENG":"You've got what you wanted. Now, give us a confirmation slip.","TWN":"東西拿到手了就趕緊把確認證明之類的給我啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아, 물론이죠. 다들 수고하셨습니다.","JPN":"あ、もちろんです。皆さん、お疲れ様でした。","ENG":"Oh, of course. Everyone, good job!","TWN":"啊，好的好的。大家辛苦了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"업무협력 확인증은 내일 발렌타인 행사 후에 찍어드리도록 하죠.","JPN":"業務協力証は、明日のバレンタイン・イベント後にお渡しします。","ENG":"I'll give you a co-op confirmation slip after the Valentine's Day event tomorrow.","TWN":"公務協力的證明書，我們會在明天情人節活動結束後簽發給大家。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"뭐? 내일? 이봐, 우린 봉사단체가 아니야.","JPN":"は？　明日？\\nちょっと、こっちはボランティア団体じゃないんだけど。","ENG":"What? Tomorrow? Hey, we're not charity workers.","TWN":"什麼? 明天？喂喂，妳當我們是志工嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"일을 맡기고 싶으면 정당한 절차를 받아서 추가 계약을 하고 맡기라고.","JPN":"仕事を任せたいなら、ちゃんとした手続きを経て追加契約をしてよ。","ENG":"If you want us to work for you again, then follow procedures and sign a new contract.","TWN":"我說你們要委託別人工作就走正規流程，簽了補充合同再來委託啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"저, 저희도 방송 계약은 오늘까지였던 걸로 알고 있는데요......","JPN":"ミ、ミヤたちも、放送の契約は今日までだと伺っているのですが……","ENG":"W-we also thought we were hired to do today's show only...","TWN":"我、我們也才知道廣播合約是到今天為止啊……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 여러분은 관리국의 성공적인 행사 개최를 위해 몸과 마음을 모두 바치기로 하고 여기에 모인 것입니다.","JPN":"何をおっしゃるんですか？　皆さんは管理局のイベントを盛り上げるために、\\nすべてを捧げるつもりでここへ集まったはずです。","ENG":"What are you talking about? You're here because you've agreed to fully commit yourself to the success of this event.","TWN":"這算什麼話？各位是為了管理局活動能成功舉辦，才聚集在這裡並決心獻出身心的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당연히 내일 행사장에서 초콜릿을 만들고 시민들에게 나눠주는 일도 여러분들의 몫이죠.","JPN":"明日イベント会場でチョコレートを作って市民に配るのも、当然皆さんのお仕事です。","ENG":"Of course, it's also your job to make chocolate and distribute it to citizens at the event site tomorrow.","TWN":"明天在活動現場向市民分發巧克力的工作，理應也是各位的職責。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"물론, 그 복장도 그대로 입고 오셔야 합니다.","JPN":"もちろん、明日も衣装は必須ですよ。","ENG":"In the same uniforms you're wearing right now, if I might add.","TWN":"當然了，各位要穿著現在這套服裝過來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"이걸...... 또 입으라고?","JPN":"これを……また着ろと言うのか？","ENG":"You want us to wear these again?","TWN":"什麼？還要穿這件衣服？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"물론이죠.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리국의 소중한 자산이니, 때가 타거나 찢어지지 않도록 주의하십시오.","JPN":"管理局の大事な財産なので、汚れたり破れたりしないようご注意ください。","ENG":"They belong to the Administration. Please be careful not to get them dirty or torn.","TWN":"這些服裝是管理局重要的資產，請小心不要弄髒或是毀壞。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_REBBIT_VAL_NULL","text":{"KOREA":"그럼 초콜릿도 저희가 직접 만드는 거죠?","JPN":"それじゃあ、チョコレートも僕たちが作るんですね？","ENG":"Then, we'll be making the chocolate too, right?","TWN":"那巧克力也是我們親自做嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARIM_REBBIT_VAL_NULL","text":{"KOREA":"완전 재미있을 것 같은데요?!","JPN":"すっごく楽しそう！","ENG":"It's going to be so fun!","TWN":"感覺非常有意思啊？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"옳은 판단이다, 대장.","JPN":"正しい判断だ、隊長。","ENG":"I concur, Captain.","TWN":"判斷的很正確呢，隊長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"예로부터 스팸과 초콜릿은 언제나 병사들의 믿음직한 친구였지.","JPN":"缶詰とチョコレートは、昔から戦闘糧食として兵士たちの頼もしい友だった。","ENG":"Spam and chocolate have long been staples for us soldiers.","TWN":"午餐肉和巧克力從前就一直是士兵忠實的朋友。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아, 물론 재미있을 겁니다.","JPN":"あ、もちろん楽しいと思います。","ENG":"Oh, of course it'll be fun.","TWN":"啊，當然會很有意思的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아주...... 아주 즐거운 시간이 될 거라고 약속 드리겠습니다.","JPN":"とても……とても楽しい時間になると約束します。","ENG":"Absolutely fun. I promise you that.","TWN":"我保證，明天一定會非常……非常有意思。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그럼 내일 행사장에서 뵙죠.","JPN":"それでは明日、会場でお会いしましょう。","ENG":"Now, I'll see you at the event site tomorrow.","TWN":"那，明天活動現場見。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};